  "questionProse": [
    "फिबोनाची सीरीज़ के साधारण (naive) रिकर्सिव इम्प्लीमेंटेशन की टाइम कॉम्प्लेक्सिटी क्या है?"
  ],
  "explanationProse": [
    "फिबोनाची सीरीज़ के साधारण रिकर्सिव इम्प्लीमेंटेशन की टाइम कॉम्प्लेक्सिटी O(2^n) होती है, क्योंकि इसमें हर फिबोनाची नंबर के लिए अत्यधिक मात्रा में गणनाएं बार-बार दोहराई जाती हैं।"
  ]
}
